+import { $internal } from '../common';
+import { destroyEntity } from '../entity/entity';
+import type { Entity } from '../entity/types';
+import { allocateEntity, isEntityAlive } from '../entity/utils/entity-index';
+import { getEntityId } from '../entity/utils/pack-entity';
+import { isRelationPair } from '../relation/utils/is-relation';
+import type { RelationPair } from '../relation/types';
+import { getRelationTargets } from '../relation/relation';
+import { addTrait, getTrait, hasTrait, removeTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait } from '../trait/types';
+import type { World } from './types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; pairs: RelationPair[] };
+
+export type DeferredBuffer = { commands: Command[]; spawned: Set<Entity> };
+
+export type DeferredCommands = {
+    spawn(...traits: ConfigurableTrait[]): Entity;
+    destroy(entity: Entity): void;
+    add(entity: Entity, ...traits: ConfigurableTrait[]): void;
+    remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void;
+    addExclusive(entity: Entity, ...pairs: RelationPair[]): void;
+    flush(): void;
+};
+
+function current(world: World) {
+    const buffers = world[$internal].deferredBuffers;
+    if (!buffers.length) buffers.push({ commands: [], spawned: new Set() });
+    return buffers[buffers.length - 1];
+}
+
+export function createDeferred(world: World): DeferredCommands {
+    return {
+        spawn(...traits) {
+            const buffer = current(world);
+            // Reserve an entity id now so it can be used by later commands, but do not
+            // make it visible to queries until its spawn command is executed.
+            const entity = allocateEntity(world[$internal].entityIndex);
+            world[$internal].entityTraits.set(entity, new Set());
+            buffer.spawned.add(entity);
+            buffer.commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) { current(world).commands.push({ type: 'destroy', entity }); },
+        add(entity, ...traits) { current(world).commands.push({ type: 'add', entity, traits }); },
+        remove(entity, ...traits) { current(world).commands.push({ type: 'remove', entity, traits }); },
+        addExclusive(entity, ...pairs) { current(world).commands.push({ type: 'exclusive', entity, pairs }); },
+        flush() { flushDeferred(world, current(world)); },
+    };
+}
+
+export function enterDeferredScope(world: World) {
+    const buffer = { commands: [], spawned: new Set<Entity>() };
+    world[$internal].deferredBuffers.push(buffer);
+    return buffer;
+}
+
+export function exitDeferredScope(world: World, buffer: DeferredBuffer) {
+    flushDeferred(world, buffer);
+    const buffers = world[$internal].deferredBuffers;
+    if (buffers[buffers.length - 1] === buffer) buffers.pop();
+}
+
+export function flushDeferredForEntity(world: World, entity: Entity) {
+    for (const buffer of [...world[$internal].deferredBuffers]) {
+        if (buffer.commands.some((command) => command.entity === entity)) flushDeferred(world, buffer);
+    }
+}
+
+export function flushDeferred(world: World, buffer: DeferredBuffer) {
+    if (!buffer.commands.length) return;
+    const commands = buffer.commands.splice(0);
+    const nullified = new Set<Entity>();
+    for (const command of commands) {
+        if (command.type === 'destroy' && buffer.spawned.has(command.entity)) nullified.add(command.entity);
+    }
+    for (const command of commands) {
+        if (nullified.has(command.entity)) continue;
+        if (command.type === 'spawn') {
+            // Deferred spawns were allocated silently. Adding their traits activates all
+            // trait-dependent queries; traitless spawns are intentionally just entities.
+            addTrait(world, command.entity, ...command.traits);
+        } else if (!isEntityAlive(world[$internal].entityIndex, command.entity)) {
+            continue;
+        } else if (command.type === 'destroy') {
+            if (command.entity === world[$internal].worldEntity) {
+                throw new Error('Koota: The world entity cannot be destroyed through deferred commands.');
+            }
+            destroyEntity(world, command.entity);
+        } else if (command.type === 'add') {
+            addTrait(world, command.entity, ...command.traits);
+        } else if (command.type === 'remove') {
+            removeTrait(world, command.entity, ...command.traits);
+        } else {
+            for (const pair of command.pairs) {
+                const relation = pair[$internal].relation;
+                const target = pair[$internal].target;
+                if (target === '*') removeTrait(world, command.entity, pair);
+                else {
+                    for (const oldTarget of getRelationTargets(world, relation, command.entity)) {
+                        removeTrait(world, command.entity, relation(oldTarget));
+                    }
+                    addTrait(world, command.entity, pair);
+                }
+            }
+        }
+    }
+    for (const entity of nullified) {
+        // It was never activated, so releasing it must not produce lifecycle events.
+        world[$internal].entityTraits.delete(entity);
+        const eid = getEntityId(entity);
+        for (const mask of world[$internal].entityMasks) mask[eid] = 0;
+        // destroyEntity cannot be used because it expects an active entity. Mark it
+        // dead through the entity index by running the ordinary destruction after a
+        // no-op activation.
+        destroyEntity(world, entity);
+    }
+    buffer.spawned.clear();
+}
+
+function projectedCommands(world: World, entity: Entity) {
+    return world[$internal].deferredBuffers.flatMap((buffer) => buffer.commands.filter((c) => c.entity === entity));
+}
+
+export function hasDeferredTrait(world: World, entity: Entity, target: Trait | RelationPair): boolean | undefined {
+    const commands = projectedCommands(world, entity);
+    if (!commands.length) return undefined;
+    let result = isRelationPair(target)
+        ? target[$internal].target === '*' ? getRelationTargets(world, target[$internal].relation, entity).length > 0 : false
+        : hasTrait(world, entity, target);
+    for (const command of commands) {
+        if (command.type === 'destroy') result = false;
+        if (command.type === 'spawn') result = false;
+        const traits = command.type === 'spawn' || command.type === 'add' ? command.traits : [];
+        for (const trait of traits) {
+            if (trait === target || (isRelationPair(trait) && isRelationPair(target) && trait[$internal].relation === target[$internal].relation && trait[$internal].target === target[$internal].target)) result = true;
+        }
+        if (command.type === 'remove') for (const trait of command.traits) {
+            if (trait === target || (isRelationPair(trait) && isRelationPair(target) && (trait[$internal].target === '*' || (trait[$internal].relation === target[$internal].relation && trait[$internal].target === target[$internal].target)))) result = false;
+        }
+        if (command.type === 'exclusive' && isRelationPair(target)) for (const pair of command.pairs) {
+            if (pair[$internal].relation === target[$internal].relation) result = pair[$internal].target === target[$internal].target;
+        }
+    }
+    return result;
+}
+
+export function getDeferredTrait(world: World, entity: Entity, target: Trait | RelationPair): any {
+    const has = hasDeferredTrait(world, entity, target);
+    if (has === undefined) return undefined;
+    if (!has) return undefined;
+    for (const command of projectedCommands(world, entity).toReversed()) {
+        if (command.type !== 'add' && command.type !== 'spawn') continue;
+        for (const config of command.traits.toReversed()) {
+            if (Array.isArray(config) && config[0] === target) return config[1];
+            if (isRelationPair(config) && isRelationPair(target) && config[$internal].relation === target[$internal].relation && config[$internal].target === target[$internal].target) return config[$internal].params;
+        }
+    }
+    return getTrait(world, entity, target);
+}
